import pygame
import sys
import random
from task0 import GameGrid, TETROMINO_SHAPES, GEM_COLORS, GRID_WIDTH, GRID_HEIGHT

# Pygame setup constants
CELL_SIZE = 30
GRID_ORIGIN = (20, 20)
PREVIEW_ORIGIN = (GRID_ORIGIN[0] + GRID_WIDTH * CELL_SIZE + 40, GRID_ORIGIN[1])
PREVIEW_SIZE = 4
SCREEN_WIDTH = GRID_ORIGIN[0] + GRID_WIDTH * CELL_SIZE + 200
SCREEN_HEIGHT = GRID_ORIGIN[1] + GRID_HEIGHT * CELL_SIZE + 40
FPS = 60
FALL_EVENT = pygame.USEREVENT + 1
FALL_INTERVAL = 500  # milliseconds

# Scoring
LINE_SCORES = {1: 100, 2: 300, 3: 500, 4: 800}
MATCH_SCORE_PER_GEM = 50

class Tetromino:
    def __init__(self, kind):
        self.kind = kind
        self.shape = TETROMINO_SHAPES[kind]
        self.color = GEM_COLORS[kind]
        self.rotation = 0
        self.x = GRID_WIDTH // 2 - 2
        self.y = 0

    def blocks(self):
        out = []
        for dx, dy in self.shape:
            x, y = dx, dy
            for _ in range(self.rotation):
                x, y = y, 3 - x
            out.append((self.x + x, self.y + y))
        return out

    def move(self, dx, dy, grid):
        if all(0 <= x + dx < grid.width and 0 <= y + dy < grid.height and
               grid.cells[y + dy][x + dx] is None for x, y in self.blocks()):
            self.x += dx
            self.y += dy
            return True
        return False

    def rotate_cw(self, grid):
        old_rot = self.rotation
        self.rotation = (self.rotation + 1) % 4
        if not all(0 <= x < grid.width and 0 <= y < grid.height and grid.cells[y][x] is None
                   for x, y in self.blocks()):
            self.rotation = old_rot

class Game:
    def __init__(self):
        pygame.init()
        self.screen = pygame.display.set_mode((SCREEN_WIDTH, SCREEN_HEIGHT))
        pygame.display.set_caption("Tetris-Bejeweled Hybrid")
        self.clock = pygame.time.Clock()
        self.font = pygame.font.SysFont(None, 36)
        self.grid = GameGrid()
        self.score = 0
        self.current = self.next_tetromino()
        self.next = self.next_tetromino()
        pygame.time.set_timer(FALL_EVENT, FALL_INTERVAL)
        self.game_over = False

    def next_tetromino(self):
        return Tetromino(random.choice(list(TETROMINO_SHAPES.keys())))

    def lock_piece(self):
        for x, y in self.current.blocks():
            self.grid.set_cell(x, y, self.current.color)
        self.clear_lines()
        self.clear_matches()
        self.current = self.next
        self.next = self.next_tetromino()
        if any(not self.grid.is_empty(x, y) for x, y in self.current.blocks()):
            self.game_over = True

    def clear_lines(self):
        full_rows = [y for y in range(self.grid.height)
                     if all(self.grid.cells[y][x] is not None for x in range(self.grid.width))]
        for y in full_rows:
            for x in range(self.grid.width):
                self.grid.clear_cell(x, y)
        for y in reversed(full_rows):
            for pull_y in range(y, 0, -1):
                for x in range(self.grid.width):
                    self.grid.cells[pull_y][x] = self.grid.cells[pull_y - 1][x]
            for x in range(self.grid.width):
                self.grid.clear_cell(x, 0)
        if full_rows:
            lines = len(full_rows)
            self.score += LINE_SCORES.get(lines, lines * 200)

    def clear_matches(self):
        chain = 0
        while True:
            to_clear = set()
            # horizontal
            for y in range(self.grid.height):
                run = []
                last_color = None
                for x in range(self.grid.width):
                    c = self.grid.cells[y][x]
                    if c and c == last_color:
                        run.append((x, y))
                    else:
                        if len(run) >= 3:
                            to_clear.update(run)
                        run = [(x, y)] if c else []
                        last_color = c
                if len(run) >= 3:
                    to_clear.update(run)
            # vertical
            for x in range(self.grid.width):
                run = []
                last_color = None
                for y in range(self.grid.height):
                    c = self.grid.cells[y][x]
                    if c and c == last_color:
                        run.append((x, y))
                    else:
                        if len(run) >= 3:
                            to_clear.update(run)
                        run = [(x, y)] if c else []
                        last_color = c
                if len(run) >= 3:
                    to_clear.update(run)
            if not to_clear:
                break
            for x, y in to_clear:
                self.grid.clear_cell(x, y)
            self.gravity()
            chain += 1
            self.score += len(to_clear) * MATCH_SCORE_PER_GEM * chain

    def gravity(self):
        for x in range(self.grid.width):
            stack = [self.grid.cells[y][x] for y in range(self.grid.height) if self.grid.cells[y][x]]
            for y in range(self.grid.height - 1, -1, -1):
                self.grid.cells[y][x] = stack.pop() if stack else None

    def handle_input(self, event):
        if event.type == pygame.KEYDOWN and not self.game_over:
            if event.key == pygame.K_LEFT:
                self.current.move(-1, 0, self.grid)
            elif event.key == pygame.K_RIGHT:
                self.current.move(1, 0, self.grid)
            elif event.key == pygame.K_DOWN:
                moved = self.current.move(0, 1, self.grid)
                if moved:
                    self.score += 1
            elif event.key == pygame.K_UP:
                self.current.rotate_cw(self.grid)
        if event.type == FALL_EVENT and not self.game_over:
            if not self.current.move(0, 1, self.grid):
                self.lock_piece()

    def draw_grid(self):
        for y in range(self.grid.height):
            for x in range(self.grid.width):
                cell = self.grid.cells[y][x]
                rect = pygame.Rect(
                    GRID_ORIGIN[0] + x * CELL_SIZE,
                    GRID_ORIGIN[1] + y * CELL_SIZE,
                    CELL_SIZE, CELL_SIZE
                )
                pygame.draw.rect(self.screen, (50, 50, 50), rect, 1)
                if cell:
                    pygame.draw.rect(self.screen, cell, rect.inflate(-2, -2))

    def draw_current(self):
        for x, y in self.current.blocks():
            rect = pygame.Rect(
                GRID_ORIGIN[0] + x * CELL_SIZE,
                GRID_ORIGIN[1] + y * CELL_SIZE,
                CELL_SIZE, CELL_SIZE
            )
            pygame.draw.rect(self.screen, self.current.color, rect.inflate(-2, -2))

    def draw_preview(self):
        label = self.font.render("Next:", True, (255, 255, 255))
        self.screen.blit(label, (PREVIEW_ORIGIN[0], PREVIEW_ORIGIN[1] - 30))
        for dx, dy in self.next.shape:
            x = PREVIEW_ORIGIN[0] + dx * CELL_SIZE
            y = PREVIEW_ORIGIN[1] + dy * CELL_SIZE
            rect = pygame.Rect(x, y, CELL_SIZE, CELL_SIZE)
            pygame.draw.rect(self.screen, (100, 100, 100), rect, 1)
            pygame.draw.rect(self.screen, self.next.color, rect.inflate(-2, -2))

    def draw_score(self):
        txt = self.font.render(f"Score: {self.score}", True, (255, 255, 255))
        self.screen.blit(txt, (PREVIEW_ORIGIN[0], PREVIEW_ORIGIN[1] + PREVIEW_SIZE * CELL_SIZE + 20))

    def draw_game_over(self):
        msg = self.font.render("GAME OVER", True, (200, 0, 0))
        rect = msg.get_rect(center=(SCREEN_WIDTH // 2, SCREEN_HEIGHT // 2))
        self.screen.blit(msg, rect)

    def run(self):
        while True:
            for event in pygame.event.get():
                if event.type == pygame.QUIT:
                    pygame.quit()
                    sys.exit()
                self.handle_input(event)
            self.screen.fill((0, 0, 0))
            self.draw_grid()
            self.draw_current()
            self.draw_preview()
            self.draw_score()
            if self.game_over:
                self.draw_game_over()
            pygame.display.flip()
            self.clock.tick(FPS)

if __name__ == "__main__":
    Game().run()
